0.这个很重要，导入导出需要先关闭，selinux,否则会报各种权限问题错误：(Errcode: 13 - Permission denied) 12mysql&gt; select * from db3.user limit 1 into outfile &quot;/mysqldatafiles/user1.txt&quot;;ERROR 1 (HY000): Can&#x27;t create/write to file &#x27;/mysqldatafiles/user1.txt&#x27; (Errcode: 13 - Permission denied) 解决： 123setenforce 0vim /etc/selinux/configSELINUX=disabled 1.数据导入与导出默认检索路径 查看默认导入导出路径默认路径：secure_file_priv - &#x2F;var&#x2F;lib&#x2F;mysql-files&#x2F; 1234567891011121314151617181920212223242526272829303132333435mysql&gt; show variables like &#x27;%file%&#x27;;+---------------------------------------+-------------------------------------+| Variable_name | Value |+---------------------------------------+-------------------------------------+| character_set_filesystem | binary || core_file | OFF || ft_stopword_file | (built-in) || general_log_file | /var/lib/mysql/centos07-12.log || init_file | || innodb_buffer_pool_filename | ib_buffer_pool || innodb_data_file_path | ibdata1:12M:autoextend || innodb_disable_sort_file_cache | OFF || innodb_file_format | Barracuda || innodb_file_format_check | ON || innodb_file_format_max | Barracuda || innodb_file_per_table | ON || innodb_log_file_size | 50331648 || innodb_log_files_in_group | 2 || innodb_open_files | 2000 || innodb_temp_data_file_path | ibtmp1:12M:autoextend || keep_files_on_create | OFF || large_files_support | ON || local_infile | ON || lower_case_file_system | OFF || myisam_max_sort_file_size | 9223372036853727232 || open_files_limit | 5000 || performance_schema_max_file_classes | 80 || performance_schema_max_file_handles | 32768 || performance_schema_max_file_instances | -1 || pid_file | /var/run/mysqld/mysqld.pid || relay_log_info_file | relay-log.info || secure_file_priv | /var/lib/mysql-files/ || slow_query_log_file | /var/lib/mysql/centos07-12-slow.log || validate_password_dictionary_file | |+---------------------------------------+-------------------------------------+ 修改12mkdir /mysqldatafileschown mysql /mysqldatafiles 1234vim /etc/my.cnfsecure_file_priv=/mysqldatafiles systemctl restart mysqld mysql中执行linux命令123456mysql&gt; system ls -l /var/总用量 8drwxr-xr-x. 2 root root 19 8月 14 15:00 accountdrwxr-xr-x. 2 root root 6 4月 11 2018 admdrwxr-xr-x. 7 root root 72 8月 14 15:00 cachedrwxr-xr-x. 2 root root 6 10月 2 2020 crash 重新登录下123456mysql&gt; show variables like &#x27;%secure_file_priv%&#x27;;+------------------+------------------+| Variable_name | Value |+------------------+------------------+| secure_file_priv | /mysqldatafiles/ |+------------------+------------------+ 2.数据导入 命令格式 infile “目录名&#x2F;文件名” # 指定导入的文件目录； fields terminated by “分隔符” # 列分隔符； lines terminated by “
”; #行分隔符，一般都
； 1load data infile &quot;目录名/文件名&quot; into table 库名.表名 fields terminated by &quot;分隔符&quot; lines terminated by &quot;
&quot;; 数据导入步骤 建库 建表(表结构根据文件内容创建) 把文件拷贝到检索目录下 导入数据 例子1234567891011create table db3.user( username char(50), password char(1), uid int, gid int, comment varchar(150), homedir char(150) , shell char( 50));load data infile &quot;/mysqldatafiles/passwd2&quot; into table db3.user fields terminated by &quot;:&quot; lines terminated by &quot;
&quot;; 如果导入报错，提示权限问题，加local错误提示：12mysql&gt; load data infile &quot;/mysqldatafiles/passwd2&quot; into table db3.user fields terminated by &quot;:&quot; lines terminated by &quot;
&quot;;ERROR 13 (HY000): Can&#x27;t get stat of &#x27;/mysqldatafiles/passwd2&#x27; (Errcode: 13 - Permission denied) 解决方式：1load data local infile &quot;/mysqldatafiles/passwd2&quot; into table db3.user fields terminated by &quot;:&quot; lines terminated by &quot;
&quot;; 3.数据导出 命令格式导出目录只要存在就可以 select 查询命令 into outfile”目录&#x2F;文件名”; select 查询命令 into outfile”目录&#x2F;文件名” fields terminated by”符号” select 查询命今 into outfile”目录&#x2F;文件名” fields terminated by “符号” lines terminated by “符号”; 例子123mysql&gt; select * from db3.user limit 2 into outfile &quot;/mysqldatafiles/user1.txt&quot;;mysql&gt; select * from db3.user limit 2 into outfile &quot;/mysqldatafiles/user2.txt&quot; fields terminated by &quot;###&quot; lines terminated by &quot;||||&quot;; 1234567[root@centos07-12 mysqldatafiles]# cat user1.txtroot x 0 0 root /root /bin/bashbin x 1 1 bin /bin /sbin/nologin [root@centos07-12 mysqldatafiles]# cat user2.txtroot###x###0###0###root###/root###/bin/bash||||bin###x###1###1###bin###/bin###/sbin/nologin||||
